#include <stdio.h>
#include <string.h>

int main() {
    int n, k;
    scanf("%d %d", &n, &k);
    char s[100001]; 
    scanf("%s", s);

    int freq[256] = {0}; // Array to count frequency of each character

    // Count frequency of each character in the string
    for (int i = 0; i < strlen(s); i++) {
        freq[(int)s[i]]++;
    }

    // Print characters with frequency >= k
    for (int i = 0; i < 256; i++) {
        if (freq[i] >= k) {
            printf("%c", i);
        }
    }

    return 0;
}

