process.stdin.resume();
process.stdin.setEncoding('utf8');

let input = '';

process.stdin.on('data', (chunk) => {
    input += chunk;
});

process.stdin.on('end', () => {
    // Split input into lines
    const lines = input.trim().split('\n');

    // Read n and k from the first line
    const [n, k] = lines[0].split(' ').map(Number);

    // Read the string from the second line
    const s = lines[1].trim();

    // Map to count character frequencies
    const freq = new Map();

    // Count the frequency of each character
    for (let ch of s) {
        freq.set(ch, (freq.get(ch) || 0) + 1);
    }

    // Use a Set to track characters that have already been added to the result
    const resultSet = new Set();

    // Iterate over the original string to maintain order
    for (let ch of s) {
        if (freq.get(ch) >= k) {
            resultSet.add(ch);
        }
    }

    // Convert the Set to an array, sort it alphabetically, and join to form the result string
    const result = Array.from(resultSet).sort().join('');

    console.log(result);
});
